class Solution:
    def checkInclusion(self, s1: str, s2: str) -> bool:
        if len(s1) > len(s2):
            return False
        s1_count = [0] * 26
        s2_count = [0] * 26
        for i in range(len(s1)):
            s1_count[ord(s1[i]) - ord('a')] += 1
            s2_count[ord(s2[i]) - ord('a')] += 1
        matches = sum(1 for i in range(26) if s1_count[i] == s2_count[i])
        for i in range(len(s1), len(s2)):
            if matches == 26:
                return True
            idx = ord(s2[i]) - ord('a')
            s2_count[idx] += 1
            if s2_count[idx] == s1_count[idx]:
                matches += 1
            elif s2_count[idx] == s1_count[idx] + 1:
                matches -= 1
            idx = ord(s2[i - len(s1)]) - ord('a')
            s2_count[idx] -= 1
            if s2_count[idx] == s1_count[idx]:
                matches += 1
            elif s2_count[idx] == s1_count[idx] - 1:
                matches -= 1
        return matches == 26

solution_js:
var checkInclusion = function(s1, s2) {
    if (s1.length > s2.length) return false;
    const s1Count = new Array(26).fill(0);
    const s2Count = new Array(26).fill(0);
    for (let i = 0; i < s1.length; i++) {
        s1Count[s1.charCodeAt(i) - 97]++;
        s2Count[s2.charCodeAt(i) - 97]++;
    }
    let matches = 0;
    for (let i = 0; i < 26; i++) if (s1Count[i] === s2Count[i]) matches++;
    for (let i = s1.length; i < s2.length; i++) {
        if (matches === 26) return true;
        let idx = s2.charCodeAt(i) - 97;
        s2Count[idx]++;
        if (s2Count[idx] === s1Count[idx]) matches++;
        else if (s2Count[idx] === s1Count[idx] + 1) matches--;
        idx = s2.charCodeAt(i - s1.length) - 97;
        s2Count[idx]--;
        if (s2Count[idx] === s1Count[idx]) matches++;
        else if (s2Count[idx] === s1Count[idx] - 1) matches--;
    }
    return matches === 26;
};

