class Solution:
    def minWindow(self, s: str, t: str) -> str:
        if not t or not s:
            return ''
        t_count = Counter(t)
        required = len(t_count)
        formed = 0
        window = {}
        ans = float('inf'), 0, 0
        l = 0
        for r in range(len(s)):
            c = s[r]
            window[c] = window.get(c, 0) + 1
            if c in t_count and window[c] == t_count[c]:
                formed += 1
            while formed == required:
                if r - l + 1 < ans[0]:
                    ans = r - l + 1, l, r
                window[s[l]] -= 1
                if s[l] in t_count and window[s[l]] < t_count[s[l]]:
                    formed -= 1
                l += 1
        return '' if ans[0] == float('inf') else s[ans[1]:ans[2] + 1]

solution_js:
var minWindow = function(s, t) {
    const tCount = {};
    for (const c of t) tCount[c] = (tCount[c] || 0) + 1;
    const required = Object.keys(tCount).length;
    let formed = 0, l = 0;
    const window = {};
    let ans = [Infinity, 0, 0];
    for (let r = 0; r < s.length; r++) {
        const c = s[r];
        window[c] = (window[c] || 0) + 1;
        if (tCount[c] && window[c] === tCount[c]) formed++;
        while (formed === required) {
            if (r - l + 1 < ans[0]) ans = [r - l + 1, l, r];
            window[s[l]]--;
            if (tCount[s[l]] && window[s[l]] < tCount[s[l]]) formed--;
            l++;
        }
    }
    return ans[0] === Infinity ? '' : s.substring(ans[1], ans[2] + 1);
};

