var findWords = function(board, words) {
    const root = {};
    for (const word of words) {
        let node = root;
        for (const c of word) {
            if (!node[c]) node[c] = {};
            node = node[c];
        }
        node.word = word;
    }
    const m = board.length, n = board[0].length;
    const result = [];
    function dfs(r, c, node) {
        if (r < 0 || r >= m || c < 0 || c >= n) return;
        const char = board[r][c];
        if (!node[char]) return;
        const next = node[char];
        if (next.word) {
            result.push(next.word);
            delete next.word;
        }
        board[r][c] = '.';
        dfs(r+1, c, next);
        dfs(r-1, c, next);
        dfs(r, c+1, next);
        dfs(r, c-1, next);
        board[r][c] = char;
        if (!Object.keys(next).length) delete node[char];
    }
    for (let r = 0; r < m; r++) {
        for (let c = 0; c < n; c++) {
            dfs(r, c, root);
        }
    }
    return result;
};

