from functools import lru_cache

class Solution:
    def isScramble(self, s1: str, s2: str) -> bool:
        @lru_cache(maxsize=None)
        def dp(a, b):
            if a == b:
                return True
            if sorted(a) != sorted(b):
                return False
            n = len(a)
            for k in range(1, n):
                # No swap
                if dp(a[:k], b[:k]) and dp(a[k:], b[k:]):
                    return True
                # Swap
                if dp(a[:k], b[n-k:]) and dp(a[k:], b[:n-k]):
                    return True
            return False
        return dp(s1, s2)

