var isScramble = function(s1, s2) {
    const memo = new Map();
    function dp(a, b) {
        if (a === b) return true;
        const key = a + '|' + b;
        if (memo.has(key)) return memo.get(key);
        if ([...a].sort().join('') !== [...b].sort().join('')) { memo.set(key, false); return false; }
        const n = a.length;
        for (let k = 1; k < n; k++) {
            if (dp(a.slice(0, k), b.slice(0, k)) && dp(a.slice(k), b.slice(k))) { memo.set(key, true); return true; }
            if (dp(a.slice(0, k), b.slice(n - k)) && dp(a.slice(k), b.slice(0, n - k))) { memo.set(key, true); return true; }
        }
        memo.set(key, false);
        return false;
    }
    return dp(s1, s2);
};

