        while (parent[x] !== x) { parent[x] = parent[parent[x]]; x = parent[x]; }
        return x;
    }
    let components = n;
    for (const [u, v] of edges) {
        const pu = find(u), pv = find(v);
        if (pu !== pv) {
            if (rank[pu] > rank[pv]) parent[pv] = pu;
            else if (rank[pu] < rank[pv]) parent[pu] = pv;
            else { parent[pv] = pu; rank[pu]++; }
            components--;
        }
    }
    return components;
};

