def validTree(self, n: int, edges: List[List[int]]) -> bool:
    if len(edges) != n - 1:
        return False
    parent = list(range(n))
    rank = [0] * n
    def find(x):
        while parent[x] != x:
            parent[x] = parent[parent[x]]
            x = parent[x]
        return x
    for u, v in edges:
        pu, pv = find(u), find(v)
        if pu == pv:
            return False
        if rank[pu] > rank[pv]:
            parent[pv] = pu
        elif rank[pu] < rank[pv]:
            parent[pu] = pv
        else:
            parent[pv] = pu
            rank[pu] += 1
    return True

