def isNStraightHand(self, hand: List[int], groupSize: int) -> bool:
    if len(hand) % groupSize:
        return False
    count = Counter(hand)
    for card in sorted(count):
        while count[card] > 0:
            for i in range(card, card + groupSize):
                if count[i] <= 0:
                    return False
                count[i] -= 1
    return True

