    const sorted = [...count.keys()].sort((a, b) => a - b);
    for (const card of sorted) {
        while (count.get(card) > 0) {
            for (let i = card; i < card + groupSize; i++) {
                if ((count.get(i) || 0) <= 0) return false;
                count.set(i, count.get(i) - 1);
            }
        }
    }
    return true;
};

