from typing import List
from collections import defaultdict, deque

class Solution:
    def findLadders(self, beginWord: str, endWord: str, wordList: List[str]) -> List[List[str]]:
        word_set = set(wordList)
        if endWord not in word_set:
            return []

        parents = defaultdict(set)
        layer = {beginWord}
        found = False

        while layer and not found:
            word_set -= layer
            next_layer = set()
            for word in layer:
                for i in range(len(word)):
                    for c in 'abcdefghijklmnopqrstuvwxyz':
                        nw = word[:i] + c + word[i+1:]
                        if nw in word_set:
                            next_layer.add(nw)
                            parents[nw].add(word)
            if endWord in next_layer:
                found = True
            layer = next_layer

        if not found:
            return []

        res = []
        def dfs(word, path):
            if word == beginWord:
                res.append(list(reversed(path)))
                return
            for parent in parents[word]:
                path.append(parent)
                dfs(parent, path)
                path.pop()

        dfs(endWord, [endWord])
        return res

solution_js:
var findLadders = function(beginWord, endWord, wordList) {
    const wordSet = new Set(wordList);
    if (!wordSet.has(endWord)) return [];

    const parents = new Map();
    let layer = new Set([beginWord]);
    let found = false;

    while (layer.size > 0 && !found) {
        layer.forEach(w => wordSet.delete(w));
        const nextLayer = new Set();
        for (const word of layer) {
            for (let i = 0; i < word.length; i++) {
                for (let c = 97; c <= 122; c++) {
                    const nw = word.slice(0, i) + String.fromCharCode(c) + word.slice(i + 1);
                    if (wordSet.has(nw)) {
                        nextLayer.add(nw);
                        if (!parents.has(nw)) parents.set(nw, new Set());
                        parents.get(nw).add(word);
                    }
                }
            }
        }
        if (nextLayer.has(endWord)) found = true;
        layer = nextLayer;
    }

    if (!found) return [];

    const res = [];
    function dfs(word, path) {
        if (word === beginWord) { res.push([...path].reverse()); return; }
        if (!parents.has(word)) return;
        for (const p of parents.get(word)) {
            path.push(p);
            dfs(p, path);
            path.pop();
        }
    }
    dfs(endWord, [endWord]);
    return res;
};

