        sign = s[i] === '-' ? -1 : 1;
        i++;
    }
    let result = 0;
    while (i < s.length && s[i] >= '0' && s[i] <= '9') {
        result = result * 10 + (s[i].charCodeAt(0) - 48);
        i++;
    }
    result *= sign;
    return Math.max(-(2**31), Math.min(2**31 - 1, result));
};

