var addBinary = function(a, b) {
    let result = [];
    let carry = 0;
    let i = a.length - 1, j = b.length - 1;
    while (i >= 0 || j >= 0 || carry) {
        let s = carry;
        if (i >= 0) s += parseInt(a[i--]);
        if (j >= 0) s += parseInt(b[j--]);
        result.push(s % 2);
        carry = Math.floor(s / 2);
    }
    return result.reverse().join('');
};

