var distanceK = function(root, target, k) {
    const parent = new Map();
    const dfs = (node, par) => {
        if (!node) return;
        parent.set(node, par);
        dfs(node.left, node);
        dfs(node.right, node);
    };
    dfs(root, null);
    let queue = [target];
    const visited = new Set([target]);
    for (let i = 0; i < k; i++) {
        const next = [];
        for (const node of queue) {
            for (const nei of [node.left, node.right, parent.get(node)]) {
                if (nei && !visited.has(nei)) {
                    visited.add(nei);
                    next.push(nei);
                }
            }
        }
        queue = next;
    }
    return queue.map(n => n.val);
};

