class Solution:
    def accountsMerge(self, accounts: List[List[str]]) -> List[List[str]]:
        parent = {}
        def find(x):
            parent.setdefault(x, x)
            if parent[x] != x:
                parent[x] = find(parent[x])
            return parent[x]
        def union(x, y):
            parent[find(x)] = find(y)
        email_to_name = {}
        for account in accounts:
            name = account[0]
            for email in account[1:]:
                email_to_name[email] = name
                union(account[1], email)
        groups = {}
        for email in email_to_name:
            root = find(email)
            groups.setdefault(root, []).append(email)
        return [[email_to_name[root]] + sorted(emails) for root, emails in groups.items()]

solution_js:
var accountsMerge = function(accounts) {
    const parent = {};
    const find = (x) => {
        if (!(x in parent)) parent[x] = x;
        if (parent[x] !== x) parent[x] = find(parent[x]);
        return parent[x];
    };
    const union = (x, y) => { parent[find(x)] = find(y); };
    const emailToName = {};
    for (const [name, ...emails] of accounts) {
        for (const email of emails) {
            emailToName[email] = name;
            union(emails[0], email);
        }
    }
    const groups = {};
    for (const email in emailToName) {
        const root = find(email);
        (groups[root] = groups[root] || []).push(email);
    }
    return Object.entries(groups).map(([root, emails]) =>
        [emailToName[root], ...emails.sort()]
    );
};

