    grid[0][0] = 1;
    for (const [r, c, dist] of queue) {
        if (r === n-1 && c === n-1) return dist;
        for (let dr = -1; dr <= 1; dr++) {
            for (let dc = -1; dc <= 1; dc++) {
                const nr = r+dr, nc = c+dc;
                if (nr >= 0 && nr < n && nc >= 0 && nc < n && grid[nr][nc] === 0) {
                    grid[nr][nc] = 1;
                    queue.push([nr, nc, dist+1]);
                }
            }
        }
    }
    return -1;
};

