class Solution:
    def gameOfLife(self, board: List[List[int]]) -> None:
        m, n = len(board), len(board[0])
        for i in range(m):
            for j in range(n):
                live = 0
                for di in (-1, 0, 1):
                    for dj in (-1, 0, 1):
                        if di == 0 and dj == 0:
                            continue
                        ni, nj = i + di, j + dj
                        if 0 <= ni < m and 0 <= nj < n and board[ni][nj] in (1, 2):
                            live += 1
                if board[i][j] == 1:
                    if live < 2 or live > 3:
                        board[i][j] = 2  # alive -> dead
                else:
                    if live == 3:
                        board[i][j] = 3  # dead -> alive
        for i in range(m):
            for j in range(n):
                board[i][j] = 1 if board[i][j] in (1, 3) else 0

solution_js:
var gameOfLife = function(board) {
    const m = board.length, n = board[0].length;
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            let live = 0;
            for (let di = -1; di <= 1; di++) {
                for (let dj = -1; dj <= 1; dj++) {
                    if (!di && !dj) continue;
                    const ni = i+di, nj = j+dj;
                    if (ni >= 0 && ni < m && nj >= 0 && nj < n && (board[ni][nj] === 1 || board[ni][nj] === 2))
                        live++;
                }
            }
            if (board[i][j] === 1 && (live < 2 || live > 3)) board[i][j] = 2;
            else if (board[i][j] === 0 && live === 3) board[i][j] = 3;
        }
    }
    for (let i = 0; i < m; i++)
        for (let j = 0; j < n; j++)
            board[i][j] = board[i][j] === 1 || board[i][j] === 3 ? 1 : 0;
};

