        const higher = Math.floor(n / (factor * 10));
        const current = Math.floor(n / factor) % 10;
        const lower = n % factor;
        if (current === 0) count += higher * factor;
        else if (current === 1) count += higher * factor + lower + 1;
        else count += (higher + 1) * factor;
    }
    return count;
};

