    for (const [state, turns] of queue) {
        if (state === target) return turns;
        for (let i = 0; i < 4; i++) {
            const d = parseInt(state[i]);
            for (const delta of [1, -1]) {
                const nd = (d + delta + 10) % 10;
                const nxt = state.slice(0, i) + nd + state.slice(i + 1);
                if (!visited.has(nxt) && !dead.has(nxt)) {
                    visited.add(nxt);
                    queue.push([nxt, turns + 1]);
                }
            }
        }
    }
    return -1;
};

