class Solution:
    def minKnightMoves(self, x: int, y: int) -> int:
        x, y = abs(x), abs(y)
        visited = {(0, 0)}
        queue = [(0, 0, 0)]
        moves = [(2,1),(2,-1),(-2,1),(-2,-1),(1,2),(1,-2),(-1,2),(-1,-2)]
        for cx, cy, steps in queue:
            if cx == x and cy == y:
                return steps
            for dx, dy in moves:
                nx, ny = cx + dx, cy + dy
                if (nx, ny) not in visited and nx >= -2 and ny >= -2:
                    visited.add((nx, ny))
                    queue.append((nx, ny, steps + 1))
        return -1

