from typing import List

class Solution:
    def singleNumber(self, nums: List[int]) -> List[int]:
        xor = 0
        for n in nums:
            xor ^= n
        diff = xor & (-xor)  # lowest set bit
        a = 0
        for n in nums:
            if n & diff:
                a ^= n
        return [a, a ^ xor]

