    const MOD = 1000000007n;
    const evenCount = BigInt((n + 1) >> 1);
    const oddCount = BigInt(n >> 1);
    function power(base, exp, mod) {
        let result = 1n;
        base = base % mod;
        while (exp > 0n) {
            if (exp % 2n === 1n) result = (result * base) % mod;
            exp = exp / 2n;
            base = (base * base) % mod;
        }
        return result;
    }
    return Number((power(5n, evenCount, MOD) * power(4n, oddCount, MOD)) % MOD);
};

