class Solution:
    def minDifficulty(self, jobDifficulty: list[int], d: int) -> int:
        n = len(jobDifficulty)
        if n < d:
            return -1
        INF = float('inf')
        dp = [[INF] * (d + 1) for _ in range(n + 1)]
        dp[0][0] = 0
        for i in range(1, n + 1):
            for k in range(1, min(i, d) + 1):
                max_diff = 0
                for j in range(i, k - 1, -1):
                    max_diff = max(max_diff, jobDifficulty[j - 1])
                    if dp[j - 1][k - 1] < INF:
                        dp[i][k] = min(dp[i][k], dp[j - 1][k - 1] + max_diff)
        return dp[n][d] if dp[n][d] < INF else -1

solution_js:
var minDifficulty = function(jobDifficulty, d) {
    const n = jobDifficulty.length;
    if (n < d) return -1;
    const INF = Infinity;
    const dp = Array.from({length: n + 1}, () => Array(d + 1).fill(INF));
    dp[0][0] = 0;
    for (let i = 1; i <= n; i++) {
        for (let k = 1; k <= Math.min(i, d); k++) {
            let maxDiff = 0;
            for (let j = i; j >= k; j--) {
                maxDiff = Math.max(maxDiff, jobDifficulty[j - 1]);
                if (dp[j - 1][k - 1] < INF) {
                    dp[i][k] = Math.min(dp[i][k], dp[j - 1][k - 1] + maxDiff);
                }
            }
        }
    }
    return dp[n][d] === INF ? -1 : dp[n][d];
};

