class Solution:
    def getPermutation(self, n: int, k: int) -> str:
        import math
        digits = list(range(1, n + 1))
        k -= 1
        result = []
        for i in range(n, 0, -1):
            fact = math.factorial(i - 1)
            idx = k // fact
            result.append(str(digits[idx]))
            digits.pop(idx)
            k %= fact
        return ''.join(result)

solution_js:
var getPermutation = function(n, k) {
    const digits = [];
    let fact = 1;
    for (let i = 1; i <= n; i++) {
        digits.push(i);
        if (i < n) fact *= i;
    }
    k--;
    let result = '';
    for (let i = n; i > 0; i--) {
        const idx = Math.floor(k / fact);
        result += digits[idx];
        digits.splice(idx, 1);
        k %= fact;
        fact = i > 1 ? Math.floor(fact / (i - 1)) : 1;
    }
    return result;
};

