    const color = new Array(graph.length).fill(-1);
    for (let i = 0; i < graph.length; i++) {
        if (color[i] !== -1) continue;
        const queue = [i];
        color[i] = 0;
        while (queue.length) {
            const curr = queue.shift();
            for (const nei of graph[curr]) {
                if (color[nei] === -1) {
                    color[nei] = 1 - color[curr];
                    queue.push(nei);
                } else if (color[nei] === color[curr]) {
                    return false;
                }
            }
        }
    }
    return true;
};

