class Solution:
    def maxPalindromes(self, s: str, k: int) -> int:
        n = len(s)
        dp = [0] * (n + 1)
        def isPalin(l, r):
            while l < r:
                if s[l] != s[r]:
                    return False
                l += 1
                r -= 1
            return True
        for i in range(n):
            dp[i + 1] = dp[i]
            for length in [k, k + 1]:
                start = i - length + 1
                if start >= 0 and isPalin(start, i):
                    dp[i + 1] = max(dp[i + 1], dp[start] + 1)
                    break
        return dp[n]

