var twistedMirrorPathCount = function(grid) {
    const m = grid.length, n = grid[0].length;
    const dirs = {'U': [-1, 0], 'D': [1, 0], 'L': [0, -1], 'R': [0, 1]};
    const reflect = {
        '/': {'U': 'R', 'D': 'L', 'L': 'D', 'R': 'U'},
        '\\': {'U': 'L', 'D': 'R', 'L': 'U', 'R': 'D'}
    };
    let count = 0;
    const entries = [];
    for (let j = 0; j < n; j++) {
        entries.push([0, j, 'D']);
        entries.push([m - 1, j, 'U']);
    }
    for (let i = 0; i < m; i++) {
        entries.push([i, 0, 'R']);
        entries.push([i, n - 1, 'L']);
    }
    for (const [sr, sc, sd] of entries) {
        let r = sr, c = sc, d = sd;
        const visited = new Set();
        while (r >= 0 && r < m && c >= 0 && c < n) {
            const key = `${r},${c},${d}`;
            if (visited.has(key)) break;
            visited.add(key);
            if (reflect[grid[r][c]]) d = reflect[grid[r][c]][d];
            const [dr, dc] = dirs[d];
            r += dr;
            c += dc;
        }
        count++;
    }
    return count;
};

