var peopleAwareOfSecret = function(n, delay, forget) {
    const MOD = 1e9 + 7;
    const dp = new Array(n + 1).fill(0);
    dp[1] = 1;
    for (let i = 2; i <= n; i++) {
        for (let j = Math.max(1, i - forget + 1); j <= i - delay; j++) {
            dp[i] = (dp[i] + dp[j]) % MOD;
        }
    }
    let result = 0;
    for (let i = n - forget + 1; i <= n; i++) {
        result = (result + dp[i]) % MOD;
    }
    return result;
};

