import heapq

class TaskManager:
    def __init__(self, tasks: list[list[int]]):
        self.heap = []
        self.tasks = {}
        for userId, taskId, priority in tasks:
            self.tasks[taskId] = (userId, priority)
            heapq.heappush(self.heap, (-priority, -taskId, userId))

    def add(self, userId: int, taskId: int, priority: int) -> None:
        self.tasks[taskId] = (userId, priority)
        heapq.heappush(self.heap, (-priority, -taskId, userId))

    def edit(self, taskId: int, newPriority: int) -> None:
        userId = self.tasks[taskId][0]
        self.tasks[taskId] = (userId, newPriority)
        heapq.heappush(self.heap, (-newPriority, -taskId, userId))

    def rmv(self, taskId: int) -> None:
        if taskId in self.tasks:
            del self.tasks[taskId]

    def execTop(self) -> int:
        while self.heap:
            neg_pri, neg_tid, userId = heapq.heappop(self.heap)
            taskId = -neg_tid
            priority = -neg_pri
            if taskId in self.tasks and self.tasks[taskId] == (userId, priority):
                del self.tasks[taskId]
                return userId
        return -1

solution_js:
var TaskManager = function(tasks) {
    this.tasks = new Map();
    this.heap = [];
    for (const [userId, taskId, priority] of tasks) {
        this.tasks.set(taskId, [userId, priority]);
        this.heap.push([-priority, -taskId, userId]);
    }
    this._heapify();
};
TaskManager.prototype._heapify = function() {
    const h = this.heap;
    for (let i = (h.length >> 1) - 1; i >= 0; i--) this._siftDown(i);
};
TaskManager.prototype._siftUp = function(i) {
    const h = this.heap;
    while (i > 0) {
        const p = (i - 1) >> 1;
        if (this._cmp(h[i], h[p]) < 0) { [h[i], h[p]] = [h[p], h[i]]; i = p; }
        else break;
    }
};
TaskManager.prototype._siftDown = function(i) {
    const h = this.heap, n = h.length;
    while (true) {
        let s = i, l = 2*i+1, r = 2*i+2;
        if (l < n && this._cmp(h[l], h[s]) < 0) s = l;
        if (r < n && this._cmp(h[r], h[s]) < 0) s = r;
        if (s !== i) { [h[i], h[s]] = [h[s], h[i]]; i = s; }
        else break;
    }
};
TaskManager.prototype._cmp = function(a, b) {
    if (a[0] !== b[0]) return a[0] - b[0];
    return a[1] - b[1];
};
TaskManager.prototype.add = function(userId, taskId, priority) {
    this.tasks.set(taskId, [userId, priority]);
    this.heap.push([-priority, -taskId, userId]);
    this._siftUp(this.heap.length - 1);
};
TaskManager.prototype.edit = function(taskId, newPriority) {
    const userId = this.tasks.get(taskId)[0];
    this.tasks.set(taskId, [userId, newPriority]);
    this.heap.push([-newPriority, -taskId, userId]);
    this._siftUp(this.heap.length - 1);
};
TaskManager.prototype.rmv = function(taskId) {
    this.tasks.delete(taskId);
};
TaskManager.prototype.execTop = function() {
    while (this.heap.length) {
        const [negPri, negTid, userId] = this.heap[0];
        this.heap[0] = this.heap[this.heap.length - 1];
        this.heap.pop();
        if (this.heap.length) this._siftDown(0);
        const taskId = -negTid, priority = -negPri;
        const entry = this.tasks.get(taskId);
        if (entry && entry[0] === userId && entry[1] === priority) {
            this.tasks.delete(taskId);
            return userId;
        }
    }
    return -1;
};

