        degree[a]++;
        degree[b]++;
        edges.add(`${Math.min(a, b)},${Math.max(a, b)}`);
    }
    let maxRank = 0;
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            let rank = degree[i] + degree[j];
            if (edges.has(`${i},${j}`)) rank--;
            maxRank = Math.max(maxRank, rank);
        }
    }
    return maxRank;
};

