    let res = 0, lastMin = -1, lastMax = -1, lastBad = -1;
    for (let i = 0; i < nums.length; i++) {
        if (nums[i] < minK || nums[i] > maxK) lastBad = i;
        if (nums[i] === minK) lastMin = i;
        if (nums[i] === maxK) lastMax = i;
        res += Math.max(0, Math.min(lastMin, lastMax) - lastBad);
