    const n = potions.length;
    const bisect = (target) => {
        let lo = 0, hi = n;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (potions[mid] < target) lo = mid + 1;
            else hi = mid;
        }
        return lo;
    };
    return spells.map(s => {
        const need = Math.ceil(success / s);
        return n - bisect(need);
    });
};

