var calcEquation = function(equations, values, queries) {
    const graph = new Map();
    for (let i = 0; i < equations.length; i++) {
        const [a, b] = equations[i];
        if (!graph.has(a)) graph.set(a, new Map());
        if (!graph.has(b)) graph.set(b, new Map());
        graph.get(a).set(b, values[i]);
        graph.get(b).set(a, 1.0 / values[i]);
    }
    function bfs(src, dst) {
        if (!graph.has(src) || !graph.has(dst)) return -1.0;
        if (src === dst) return 1.0;
        const visited = new Set([src]);
        const queue = [[src, 1.0]];
        while (queue.length) {
            const [node, prod] = queue.shift();
            for (const [neighbor, weight] of graph.get(node)) {
                if (neighbor === dst) return prod * weight;
                if (!visited.has(neighbor)) {
                    visited.add(neighbor);
                    queue.push([neighbor, prod * weight]);
                }
            }
        }
        return -1.0;
    }
    return queries.map(([a, b]) => bfs(a, b));
};

var reorganizeString = function(s) {
    const counts = {};
    for (const c of s) counts[c] = (counts[c] || 0) + 1;
    const maxHeap = Object.entries(counts).map(([ch, cnt]) => [cnt, ch]);
    maxHeap.sort((a, b) => b[0] - a[0]);
    const result = [];
    while (maxHeap.length > 0) {
        maxHeap.sort((a, b) => b[0] - a[0]);
        const [cnt1, ch1] = maxHeap.shift();
        if (result.length > 0 && result[result.length - 1] === ch1) {
            if (maxHeap.length === 0) return '';
            const [cnt2, ch2] = maxHeap.shift();
            result.push(ch2);
            if (cnt2 - 1 > 0) maxHeap.push([cnt2 - 1, ch2]);
            maxHeap.push([cnt1, ch1]);
        } else {
            result.push(ch1);
            if (cnt1 - 1 > 0) maxHeap.push([cnt1 - 1, ch1]);
        }
    }
    return result.join('');
};

