class Solution:
    def flatten(self, head: 'Optional[Node]') -> 'Optional[Node]':
        if not head:
            return head
        curr = head
        while curr:
            if curr.child:
                child = curr.child
                # Find tail of child list
                tail = child
                while tail.next:
                    tail = tail.next
                # Splice child list
                tail.next = curr.next
                if curr.next:
                    curr.next.prev = tail
                curr.next = child
                child.prev = curr
                curr.child = None
            curr = curr.next
        return head

