            let tail = child;
            while (tail.next) tail = tail.next;
            tail.next = curr.next;
            if (curr.next) curr.next.prev = tail;
            curr.next = child;
            child.prev = curr;
            curr.child = null;
        }
        curr = curr.next;
    }
    return head;
};

