        graph[v].add(u);
    }
    const result = [];
    for (const q of queries) {
        const visited = new Set([q]);
        let maxComp = 0;
        for (let start = 0; start < n; start++) {
            if (!visited.has(start)) {
                const queue = [start];
                visited.add(start);
                let comp = 0, i = 0;
                while (i < queue.length) {
                    const node = queue[i++];
                    comp++;
                    for (const nei of graph[node]) {
                        if (!visited.has(nei)) {
                            visited.add(nei);
                            queue.push(nei);
                        }
                    }
                }
                maxComp = Math.max(maxComp, comp);
            }
        }
        result.push(maxComp);
    }
    return result;
};

