var maxRotateFunction = function(nums) {
    const n = nums.length;
    const total = nums.reduce((a, b) => a + b, 0);
    let f = nums.reduce((acc, val, i) => acc + i * val, 0);
    let maxF = f;
    for (let k = 1; k < n; k++) {
        f = f + total - n * nums[n - k];
        maxF = Math.max(maxF, f);
    }
    return maxF;
};

