var calculate = function(s) {
    const stack = [];
    let result = 0, num = 0, sign = 1;
    for (const ch of s) {
        if (ch >= '0' && ch <= '9') {
            num = num * 10 + Number(ch);
        } else if (ch === '+') {
            result += sign * num;
            num = 0;
            sign = 1;
        } else if (ch === '-') {
            result += sign * num;
            num = 0;
            sign = -1;
        } else if (ch === '(') {
            stack.push(result);
            stack.push(sign);
            result = 0;
            sign = 1;
        } else if (ch === ')') {
            result += sign * num;
            num = 0;
            result *= stack.pop();
            result += stack.pop();
        }
    }
    result += sign * num;
    return result;
};

