    const m = str1.length, n = str2.length;
    const dp = Array.from({length: m + 1}, () => Array(n + 1).fill(''));
    for (let i = 1; i <= m; i++) {
        for (let j = 1; j <= n; j++) {
            if (str1[i-1] === str2[j-1]) {
                dp[i][j] = dp[i-1][j-1] + str1[i-1];
            } else {
                dp[i][j] = dp[i-1][j].length > dp[i][j-1].length ? dp[i-1][j] : dp[i][j-1];
            }
        }
    }
    const lcs = dp[m][n];
    const res = [];
    let i = 0, j = 0;
    for (const c of lcs) {
        while (i < m && str1[i] !== c) res.push(str1[i++]);
        while (j < n && str2[j] !== c) res.push(str2[j++]);
        res.push(c);
        i++;
        j++;
    }
    res.push(str1.slice(i));
    res.push(str2.slice(j));
    return res.join('');
};

