            y += dy;
        } else if (ch === 'L') {
            [dx, dy] = [-dy, dx];
        } else {
            [dx, dy] = [dy, -dx];
        }
    }
    return (x === 0 && y === 0) || (dx !== 0 || dy !== 1);
};

