class Solution:
    def intersectionSizeTwo(self, intervals: List[List[int]]) -> int:
        intervals.sort(key=lambda x: (x[1], -x[0]))
        res = []
        for s, e in intervals:
            if not res or res[-1] < s:
                res.extend([e - 1, e])
            elif res[-2] < s:
                if res[-1] == e:
                    res.append(res[-1])
                    res[-2] = e - 1
                else:
                    res.append(e)
        return len(res)

