    for (const [s, e] of intervals) {
        const n = res.length;
        if (res[n - 1] < s) {
            res.push(e - 1, e);
            count += 2;
        } else if (res[n - 2] < s) {
            if (res[n - 1] === e) {
                res.push(e);
                res[res.length - 2] = e - 1;
            } else {
                res.push(e);
            }
            count++;
        }
    }
    return count;
};

