class Solution:
    def numberOfPaths(self, grid: list[list[int]], k: int) -> int:
        MOD = 10**9 + 7
        m, n = len(grid), len(grid[0])
        dp = [[[0] * k for _ in range(n)] for _ in range(m)]
        dp[0][0][grid[0][0] % k] = 1
        for i in range(m):
            for j in range(n):
                if i == 0 and j == 0:
                    continue
                for r in range(k):
                    nr = (r + grid[i][j]) % k
                    if i > 0:
                        dp[i][j][nr] = (dp[i][j][nr] + dp[i - 1][j][r]) % MOD
                    if j > 0:
                        dp[i][j][nr] = (dp[i][j][nr] + dp[i][j - 1][r]) % MOD
        return dp[m - 1][n - 1][0]

