    const MOD = 1e9 + 7;
    const m = grid.length, n = grid[0].length;
    const dp = Array.from({length: m}, () => Array.from({length: n}, () => new Array(k).fill(0)));
    dp[0][0][grid[0][0] % k] = 1;
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (i === 0 && j === 0) continue;
            for (let r = 0; r < k; r++) {
                const nr = (r + grid[i][j]) % k;
                if (i > 0) dp[i][j][nr] = (dp[i][j][nr] + dp[i - 1][j][r]) % MOD;
                if (j > 0) dp[i][j][nr] = (dp[i][j][nr] + dp[i][j - 1][r]) % MOD;
            }
        }
    }
    return dp[m - 1][n - 1][0];
};

