var palindromePairs = function(words) {
    const isPalin = (s, lo, hi) => {
        while (lo < hi) {
            if (s[lo] !== s[hi]) return false;
            lo++; hi--;
        }
        return true;
    };
    const map = new Map();
    for (let i = 0; i < words.length; i++) {
        map.set(words[i].split('').reverse().join(''), i);
    }
    const result = [];
    for (let i = 0; i < words.length; i++) {
        const word = words[i];
        const n = word.length;
        for (let j = 0; j <= n; j++) {
            const prefix = word.substring(0, j);
            const suffix = word.substring(j);
            if (map.has(prefix) && map.get(prefix) !== i && isPalin(word, j, n - 1)) {
                result.push([i, map.get(prefix)]);
            }
            if (j > 0 && map.has(suffix) && map.get(suffix) !== i && isPalin(word, 0, j - 1)) {
                result.push([map.get(suffix), i]);
            }
        }
    }
    return result;
};

