class Solution:
    def countMentions(self, numberOfUsers: int, events: list[list[str]]) -> list[int]:
        events.sort(key=lambda e: (int(e[1]), 0 if e[0] == 'OFFLINE' else 1))
        mentions = [0] * numberOfUsers
        online_time = [0] * numberOfUsers
        for event in events:
            typ, ts_str, msg = event
            ts = int(ts_str)
            if typ == 'OFFLINE':
                user_id = int(msg)
                online_time[user_id] = ts + 60
            elif typ == 'MESSAGE':
                if msg == 'ALL':
                    for i in range(numberOfUsers):
                        mentions[i] += 1
                elif msg == 'HERE':
                    for i in range(numberOfUsers):
                        if online_time[i] <= ts:
                            mentions[i] += 1
                else:
                    for uid_str in msg.split():
                        uid = int(uid_str[2:])
                        mentions[uid] += 1
        return mentions

