class Solution:
    def findMaximumXOR(self, nums: list[int]) -> int:
        # Build a trie of all numbers
        max_num = max(nums)
        if max_num == 0:
            return 0
        L = max_num.bit_length()

        # Use dictionary-based trie
        trie = {}
        for num in nums:
            node = trie
            for i in range(L, -1, -1):
                bit = (num >> i) & 1
                if bit not in node:
                    node[bit] = {}
                node = node[bit]

        max_xor = 0
        for num in nums:
            node = trie
            curr_xor = 0
            for i in range(L, -1, -1):
                bit = (num >> i) & 1
                # Try to go opposite direction
                toggled = 1 - bit
                if toggled in node:
                    curr_xor = (curr_xor << 1) | 1
                    node = node[toggled]
                else:
                    curr_xor = curr_xor << 1
                    node = node[bit]
            max_xor = max(max_xor, curr_xor)

        return max_xor

solution_js:
/**
 * @param {number[]} nums
 * @return {number}
 */
var findMaximumXOR = function(nums) {
    const maxNum = Math.max(...nums);
    if (maxNum === 0) return 0;
    const L = maxNum.toString(2).length;

    // Build trie
    const trie = {};
    for (const num of nums) {
        let node = trie;
        for (let i = L; i >= 0; i--) {
            const bit = (num >> i) & 1;
            if (!(bit in node)) node[bit] = {};
            node = node[bit];
        }
    }

    let maxXor = 0;
    for (const num of nums) {
        let node = trie;
        let currXor = 0;
        for (let i = L; i >= 0; i--) {
            const bit = (num >> i) & 1;
            const toggled = 1 - bit;
            if (toggled in node) {
                currXor = (currXor << 1) | 1;
                node = node[toggled];
            } else {
                currXor = currXor << 1;
                node = node[bit];
            }
        }
        maxXor = Math.max(maxXor, currXor);
    }

    return maxXor;
};

