CustomStack.prototype.pop = function() {
    if (this.stack.length === 0) return -1;
    const idx = this.stack.length - 1;
    const val = this.stack.pop() + this.inc[idx];
    if (idx > 0) this.inc[idx - 1] += this.inc[idx];
    this.inc.pop();
