class Solution:
    def minimumTimeRequired(self, jobs: list[int], k: int) -> int:
        jobs.sort(reverse=True)
        workers = [0] * k
        self.ans = sum(jobs)

        def backtrack(idx):
            if idx == len(jobs):
                self.ans = min(self.ans, max(workers))
                return
            seen = set()
            for i in range(k):
                if workers[i] + jobs[idx] >= self.ans:
                    continue
                if workers[i] in seen:
                    continue
                seen.add(workers[i])
                workers[i] += jobs[idx]
                backtrack(idx + 1)
                workers[i] -= jobs[idx]

        backtrack(0)
        return self.ans

solution_js:
var minimumTimeRequired = function(jobs, k) {
    jobs.sort((a, b) => b - a);
    const workers = new Array(k).fill(0);
    let ans = jobs.reduce((a, b) => a + b, 0);
    const backtrack = (idx) => {
        if (idx === jobs.length) {
            ans = Math.min(ans, Math.max(...workers));
            return;
        }
        const seen = new Set();
        for (let i = 0; i < k; i++) {
            if (workers[i] + jobs[idx] >= ans) continue;
            if (seen.has(workers[i])) continue;
            seen.add(workers[i]);
            workers[i] += jobs[idx];
            backtrack(idx + 1);
            workers[i] -= jobs[idx];
        }
    };
    backtrack(0);
    return ans;
};

