class Solution:
    def shortestBridge(self, grid: list[list[int]]) -> int:
        n = len(grid)
        visited = [[False] * n for _ in range(n)]
        directions = [(0,1),(0,-1),(1,0),(-1,0)]
        queue = []
        def dfs(r, c):
            if r < 0 or r >= n or c < 0 or c >= n or visited[r][c] or grid[r][c] == 0:
                return
            visited[r][c] = True
            queue.append((r, c))
            for dr, dc in directions:
                dfs(r + dr, c + dc)
        found = False
        for i in range(n):
            if found:
                break
            for j in range(n):
                if grid[i][j] == 1:
                    dfs(i, j)
                    found = True
                    break
        level = 0
        while queue:
            next_queue = []
            for r, c in queue:
                for dr, dc in directions:
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < n and 0 <= nc < n and not visited[nr][nc]:
                        if grid[nr][nc] == 1:
                            return level
                        visited[nr][nc] = True
                        next_queue.append((nr, nc))
            queue = next_queue
            level += 1
        return -1

solution_js:
var shortestBridge = function(grid) {
    const n = grid.length;
    const visited = Array.from({length: n}, () => Array(n).fill(false));
    const dirs = [[0,1],[0,-1],[1,0],[-1,0]];
    let queue = [];
    const dfs = (r, c) => {
        if (r < 0 || r >= n || c < 0 || c >= n || visited[r][c] || grid[r][c] === 0) return;
        visited[r][c] = true;
        queue.push([r, c]);
        for (const [dr, dc] of dirs) dfs(r + dr, c + dc);
    };
    let found = false;
    for (let i = 0; i < n && !found; i++) {
        for (let j = 0; j < n && !found; j++) {
            if (grid[i][j] === 1) { dfs(i, j); found = true; }
        }
    }
    let level = 0;
    while (queue.length) {
        const next = [];
        for (const [r, c] of queue) {
            for (const [dr, dc] of dirs) {
                const nr = r + dr, nc = c + dc;
                if (nr >= 0 && nr < n && nc >= 0 && nc < n && !visited[nr][nc]) {
                    if (grid[nr][nc] === 1) return level;
                    visited[nr][nc] = true;
                    next.push([nr, nc]);
                }
            }
        }
        queue = next;
        level++;
    }
    return -1;
};

