class Solution:
    def longestIdealString(self, s: str, k: int) -> int:
        dp = [0] * 26
        for ch in s:
            idx = ord(ch) - ord('a')
            best = 0
            for j in range(max(0, idx - k), min(26, idx + k + 1)):
                best = max(best, dp[j])
            dp[idx] = best + 1
        return max(dp)

