    def beautifulIndices(self, s: str, a: str, b: str, k: int) -> list[int]:
        def find_all(text, pattern):
            indices = []
            start = 0
            while True:
                idx = text.find(pattern, start)
                if idx == -1:
                    break
                indices.append(idx)
                start = idx + 1
            return indices
        a_indices = find_all(s, a)
        b_indices = find_all(s, b)
        result = []
        j = 0
        for i_a in a_indices:
            while j < len(b_indices) and b_indices[j] < i_a - k:
                j += 1
            if j < len(b_indices) and abs(b_indices[j] - i_a) <= k:
                result.append(i_a)
        return result

