            if (idx === -1) break;
            indices.push(idx);
            start = idx + 1;
        }
        return indices;
    };
    const aIdx = findAll(s, a);
    const bIdx = findAll(s, b);
    const result = [];
    let j = 0;
    for (const ia of aIdx) {
        while (j < bIdx.length && bIdx[j] < ia - k) j++;
        if (j < bIdx.length && Math.abs(bIdx[j] - ia) <= k) result.push(ia);
    }
    return result;
};

