class Solution:
    def validIPAddress(self, queryIP: str) -> str:
        def is_valid_ipv4(s):
            parts = s.split('.')
            if len(parts) != 4:
                return False
            for part in parts:
                if not part or not part.isdigit():
                    return False
                if part != str(int(part)):  # leading zeros
                    return False
                if not 0 <= int(part) <= 255:
                    return False
            return True

        def is_valid_ipv6(s):
            parts = s.split(':')
            if len(parts) != 8:
                return False
            hex_chars = set('0123456789abcdefABCDEF')
            for part in parts:
                if not 1 <= len(part) <= 4:
                    return False
                if not all(c in hex_chars for c in part):
                    return False
            return True

        if '.' in queryIP:
            return 'IPv4' if is_valid_ipv4(queryIP) else 'Neither'
        elif ':' in queryIP:
            return 'IPv6' if is_valid_ipv6(queryIP) else 'Neither'
        return 'Neither'

solution_js:
var validIPAddress = function(queryIP) {
    function isIPv4(s) {
        const parts = s.split('.');
        if (parts.length !== 4) return false;
        for (const p of parts) {
            if (!p || !/^\d+$/.test(p)) return false;
            if (p !== String(parseInt(p, 10))) return false;
            if (parseInt(p, 10) < 0 || parseInt(p, 10) > 255) return false;
        }
        return true;
    }
    function isIPv6(s) {
        const parts = s.split(':');
        if (parts.length !== 8) return false;
        for (const p of parts) {
            if (p.length < 1 || p.length > 4) return false;
            if (!/^[0-9a-fA-F]+$/.test(p)) return false;
        }
        return true;
    }
    if (queryIP.includes('.')) return isIPv4(queryIP) ? 'IPv4' : 'Neither';
    if (queryIP.includes(':')) return isIPv6(queryIP) ? 'IPv6' : 'Neither';
    return 'Neither';
};

