class Solution:
    def minimumPairRemoval(self, nums: list[int]) -> int:
        import heapq
        from sortedcontainers import SortedList
        n = len(nums)
        vals = list(nums)
        prev = list(range(-1, n - 1))
        nxt = list(range(1, n + 1))
        alive = [True] * n
        bad = 0
        for i in range(n - 1):
            if vals[i] > vals[i + 1]:
                bad += 1
        heap = []
        for i in range(n - 1):
            heapq.heappush(heap, (vals[i] + vals[i + 1], i, i + 1))
        ops = 0
        while bad > 0:
            while heap:
                s, l, r = heapq.heappop(heap)
                if alive[l] and alive[r] and nxt[l] == r and vals[l] + vals[r] == s:
                    break
            else:
                break
            p = prev[l]
            nr = nxt[r]
            if p >= 0 and vals[p] > vals[l]:
                bad -= 1
            if vals[l] > vals[r]:
                bad -= 1
            if nr < n and vals[r] > vals[nr]:
                bad -= 1
            vals[l] = vals[l] + vals[r]
            alive[r] = False
            nxt[l] = nr
            if nr < n:
                prev[nr] = l
            if p >= 0 and vals[p] > vals[l]:
                bad += 1
            if nr < n and vals[l] > vals[nr]:
                bad += 1
            if p >= 0:
                heapq.heappush(heap, (vals[p] + vals[l], p, l))
            if nr < n:
                heapq.heappush(heap, (vals[l] + vals[nr], l, nr))
            ops += 1
        return ops

