            heap.enqueue(events[i][1]);
            i++;
        }
        while (!heap.isEmpty() && heap.front().element < day) {
            heap.dequeue();
        }
        if (!heap.isEmpty()) {
            heap.dequeue();
            res++;
        }
        day++;
    }
