class Solution:
    def findRadius(self, houses: list[int], heaters: list[int]) -> int:
        import bisect
        heaters.sort()
        res = 0
        for h in houses:
            i = bisect.bisect_left(heaters, h)
            dist = float('inf')
            if i < len(heaters):
                dist = min(dist, heaters[i] - h)
            if i > 0:
                dist = min(dist, h - heaters[i - 1])
            res = max(res, dist)
        return res

