    this.anti = 0;
};

TicTacToe.prototype.move = function(row, col, player) {
    const val = player === 1 ? 1 : -1;
    this.rows[row] += val;
    this.cols[col] += val;
    if (row === col) this.diag += val;
    if (row + col === this.n - 1) this.anti += val;
    if (Math.abs(this.rows[row]) === this.n || Math.abs(this.cols[col]) === this.n || Math.abs(this.diag) === this.n || Math.abs(this.anti) === this.n) return player;
    return 0;
};

