var treeDiameter = function(edges) {
    if (!edges.length) return 0;
    const graph = {};
    for (const [u, v] of edges) {
        (graph[u] = graph[u] || []).push(v);
        (graph[v] = graph[v] || []).push(u);
    }
    function bfs(start) {
        const dist = {[start]: 0};
        const q = [start];
        let farthest = start;
        let i = 0;
        while (i < q.length) {
            const node = q[i++];
            for (const nei of (graph[node] || [])) {
                if (dist[nei] === undefined) {
                    dist[nei] = dist[node] + 1;
                    q.push(nei);
                    if (dist[nei] > dist[farthest]) farthest = nei;
                }
            }
        }
        return [farthest, dist[farthest]];
    }
    const [u] = bfs(0);
    const [, d] = bfs(u);
    return d;
};

