class Solution:
    def minTaps(self, n: int, ranges: list[int]) -> int:
        maxReach = [0] * (n + 1)
        for i, r in enumerate(ranges):
            left = max(0, i - r)
            right = min(n, i + r)
            maxReach[left] = max(maxReach[left], right)
        taps = 0
        curEnd = 0
        farEnd = 0
        for i in range(n + 1):
            if i > farEnd:
                return -1
            farEnd = max(farEnd, maxReach[i])
            if i == curEnd and i < n:
                taps += 1
                curEnd = farEnd
        return taps

