    for (let i = 1; i <= high; i++) {
        if (i >= zero) dp[i] = (dp[i] + dp[i - zero]) % MOD;
        if (i >= one) dp[i] = (dp[i] + dp[i - one]) % MOD;
    }
    let res = 0;
    for (let i = low; i <= high; i++) res = (res + dp[i]) % MOD;
    return res;
};

