class Solution:
    def getCollisionTimes(self, cars: list[list[int]]) -> list[float]:
        n = len(cars)
        res = [-1.0] * n
        stack = []
        for i in range(n - 1, -1, -1):
            pos, speed = cars[i]
            while stack:
                j = stack[-1]
                if speed <= cars[j][1]:
                    stack.pop()
                else:
                    t = (cars[j][0] - pos) / (speed - cars[j][1])
                    if res[j] < 0 or t <= res[j]:
                        res[i] = t
                        break
                    stack.pop()
            stack.append(i)
        return res

