class Solution:
    def nearestPalindromic(self, n: str) -> str:
        length = len(n)
        num = int(n)
        candidates = set()
        candidates.add(10 ** (length - 1) - 1)
        candidates.add(10 ** length + 1)
        prefix = int(n[:(length + 1) // 2])
        for delta in [-1, 0, 1]:
            p = str(prefix + delta)
            if length % 2 == 0:
                candidate = p + p[::-1]
            else:
                candidate = p + p[-2::-1]
            candidates.add(int(candidate))
        candidates.discard(num)
        closest = None
        for c in candidates:
            if closest is None or abs(c - num) < abs(closest - num) or (abs(c - num) == abs(closest - num) and c < closest):
                closest = c
        return str(closest)

