var nearestPalindromic = function(n) {
    const len = n.length;
    const num = BigInt(n);
    const candidates = new Set();
    candidates.add(BigInt(10) ** BigInt(len - 1) - 1n);
    candidates.add(BigInt(10) ** BigInt(len) + 1n);
    const prefix = BigInt(n.substring(0, Math.ceil(len / 2)));
    for (const delta of [-1n, 0n, 1n]) {
        const p = (prefix + delta).toString();
        let candidate;
        if (len % 2 === 0) {
            candidate = p + p.split('').reverse().join('');
        } else {
            candidate = p + p.slice(0, -1).split('').reverse().join('');
        }
        candidates.add(BigInt(candidate));
    }
    candidates.delete(num);
    let closest = null;
    for (const c of candidates) {
        const diff = c > num ? c - num : num - c;
        const bestDiff = closest !== null ? (closest > num ? closest - num : num - closest) : null;
        if (closest === null || diff < bestDiff || (diff === bestDiff && c < closest)) {
            closest = c;
        }
    }
    return closest.toString();
};

