            currentNum = currentNum * 10 + Number(ch);
        } else if (ch === '[') {
            stack.push([currentStr, currentNum]);
            currentStr = ''; currentNum = 0;
        } else if (ch === ']') {
            const [prevStr, k] = stack.pop();
            currentStr = prevStr + currentStr.repeat(k);
        } else {
            currentStr += ch;
        }
    }
    return currentStr;
};

