class Solution:
    def splitArray(self, nums: List[int], k: int) -> int:
        def feasible(max_sum):
            count, current = 1, 0
            for num in nums:
                if current + num > max_sum:
                    count += 1
                    current = 0
                current += num
            return count <= k

        lo, hi = max(nums), sum(nums)
        while lo < hi:
            mid = (lo + hi) // 2
            if feasible(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo

