from typing import List
from functools import lru_cache

class Solution:
    def removeBoxes(self, boxes: List[int]) -> int:
        @lru_cache(maxsize=None)
        def dp(l, r, k):
            if l > r:
                return 0
            # Merge consecutive same boxes at the left
            while l < r and boxes[l] == boxes[l + 1]:
                l += 1
                k += 1
            # Option 1: remove the l group now
            res = (k + 1) * (k + 1) + dp(l + 1, r, 0)
            # Option 2: merge with a matching box later
            for m in range(l + 1, r + 1):
                if boxes[m] == boxes[l]:
                    res = max(res, dp(l + 1, m - 1, 0) + dp(m, r, k + 1))
            return res
        return dp(0, len(boxes) - 1, 0)

solution_js:
var removeBoxes = function(boxes) {
    const n = boxes.length;
    const memo = {};
    function dp(l, r, k) {
        if (l > r) return 0;
        const key = `${l},${r},${k}`;
        if (memo[key] !== undefined) return memo[key];
        // Collapse consecutive same at left
        while (l < r && boxes[l] === boxes[l + 1]) { l++; k++; }
        let res = (k + 1) * (k + 1) + dp(l + 1, r, 0);
        for (let m = l + 1; m <= r; m++) {
            if (boxes[m] === boxes[l]) {
                res = Math.max(res, dp(l + 1, m - 1, 0) + dp(m, r, k + 1));
            }
        }
        memo[`${l},${r},${k}`] = res;
        return res;
    }
    return dp(0, n - 1, 0);
};

