import heapq
class Solution:
    def minCost(self, n: int, roads: List[List[int]], libraries: List[List[int]]) -> int:
        graph = [[] for _ in range(n * n)]
        for r in range(n):
            for c in range(n):
                node = r * n + c
                if r + 1 < n: graph[node].append((node + n, 1))
                if c + 1 < n: graph[node].append((node + 1, 1))
        portal_map = {}
        for a, b in libraries:
            portal_map.setdefault(a, []).append(b)
            portal_map.setdefault(b, []).append(a)
        for src, dsts in portal_map.items():
            for dst in dsts:
                graph[src].append((dst, 0))
        dist = [float('inf')] * (n * n)
        dist[0] = 0
        pq = [(0, 0)]
        while pq:
            d, u = heapq.heappop(pq)
            if d > dist[u]: continue
            for v, w in graph[u]:
                if dist[u] + w < dist[v]:
                    dist[v] = dist[u] + w
                    heapq.heappush(pq, (dist[v], v))
        return dist[n * n - 1]

solution_js:
var minCost = function(n, roads, libraries) {
    const graph = Array.from({length: n * n}, () => []);
    for (let r = 0; r < n; r++) {
        for (let c = 0; c < n; c++) {
            const node = r * n + c;
            if (r + 1 < n) graph[node].push([node + n, 1]);
            if (c + 1 < n) graph[node].push([node + 1, 1]);
        }
    }
    for (const [a, b] of libraries) {
        graph[a].push([b, 0]);
        graph[b].push([a, 0]);
    }
    const dist = new Array(n * n).fill(Infinity);
    dist[0] = 0;
    const pq = [[0, 0]];
    while (pq.length) {
        pq.sort((a, b) => a[0] - b[0]);
        const [d, u] = pq.shift();
        if (d > dist[u]) continue;
        for (const [v, w] of graph[u]) {
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                pq.push([dist[v], v]);
            }
        }
    }
    return dist[n * n - 1];
};

