var hasGroupsSizeX = function(deck) {
    const freq = new Map();
    for (const c of deck) freq.set(c, (freq.get(c) || 0) + 1);
    function gcd(a, b) { return b === 0 ? a : gcd(b, a % b); }
    let g = 0;
    for (const v of freq.values()) g = gcd(g, v);
    return g >= 2;
};

