from sortedcontainers import SortedList
class RangeModule:
    def __init__(self):
        self.ranges = SortedList(key=lambda x: x[0])

    def addRange(self, left: int, right: int) -> None:
        to_remove = []
        for r in self.ranges.irange((left, -1), (right, float('inf')), (True, True)):
            if r[1] >= left and r[0] <= right:
                left = min(left, r[0])
                right = max(right, r[1])
                to_remove.append(r)
        for r in to_remove: self.ranges.remove(r)
        self.ranges.add((left, right))

    def queryRange(self, left: int, right: int) -> bool:
        idx = self.ranges.bisect_right((left, float('inf'))) - 1
        if idx < 0: return False
        r = self.ranges[idx]
        return r[0] <= left and r[1] >= right

    def removeRange(self, left: int, right: int) -> None:
        to_remove = []
        to_add = []
        for r in list(self.ranges):
            if r[1] <= left or r[0] >= right: continue
            to_remove.append(r)
            if r[0] < left: to_add.append((r[0], left))
            if r[1] > right: to_add.append((right, r[1]))
        for r in to_remove: self.ranges.remove(r)
        for r in to_add: self.ranges.add(r)

solution_js:
class RangeModule {
    constructor() { this.ranges = []; }
    addRange(left, right) {
        const res = [];
        let inserted = false;
        for (const [l, r] of this.ranges) {
            if (r < left) { res.push([l, r]); }
            else if (l > right) {
                if (!inserted) { res.push([left, right]); inserted = true; }
                res.push([l, r]);
            } else {
                left = Math.min(left, l);
                right = Math.max(right, r);
            }
        }
        if (!inserted) res.push([left, right]);
        this.ranges = res;
    }
    queryRange(left, right) {
        for (const [l, r] of this.ranges)
            if (l <= left && r >= right) return true;
        return false;
    }
    removeRange(left, right) {
        const res = [];
        for (const [l, r] of this.ranges) {
            if (r <= left || l >= right) { res.push([l, r]); }
            else {
                if (l < left) res.push([l, left]);
                if (r > right) res.push([right, r]);
            }
        }
        this.ranges = res;
    }
}

