class Solution:
    def latestDayToCross(self, row: int, col: int, cells: List[List[int]]) -> int:
        from collections import deque
        def canCross(day):
            grid = [[0]*col for _ in range(row)]
            for r, c in cells[:day]:
                grid[r-1][c-1] = 1
            queue = deque()
            for c in range(col):
                if grid[0][c] == 0:
                    queue.append((0, c))
                    grid[0][c] = -1
            while queue:
                r, c = queue.popleft()
                if r == row - 1:
                    return True
                for dr, dc in [(1,0),(-1,0),(0,1),(0,-1)]:
                    nr, nc = r+dr, c+dc
                    if 0 <= nr < row and 0 <= nc < col and grid[nr][nc] == 0:
                        grid[nr][nc] = -1
                        queue.append((nr, nc))
            return False
        lo, hi = 1, len(cells)
        while lo < hi:
            mid = (lo + hi + 1) // 2
            if canCross(mid):
                lo = mid
            else:
                hi = mid - 1
        return lo

solution_js:
var latestDayToCross = function(row, col, cells) {
    function canCross(day) {
        const grid = Array.from({length: row}, () => new Array(col).fill(0));
        for (let i = 0; i < day; i++) grid[cells[i][0]-1][cells[i][1]-1] = 1;
        const queue = [];
        for (let c = 0; c < col; c++) if (grid[0][c] === 0) { queue.push([0, c]); grid[0][c] = -1; }
        let qi = 0;
        while (qi < queue.length) {
            const [r, c] = queue[qi++];
            if (r === row - 1) return true;
            for (const [dr, dc] of [[1,0],[-1,0],[0,1],[0,-1]]) {
                const nr = r+dr, nc = c+dc;
                if (nr >= 0 && nr < row && nc >= 0 && nc < col && grid[nr][nc] === 0) {
                    grid[nr][nc] = -1;
                    queue.push([nr, nc]);
                }
            }
        }
        return false;
    }
    let lo = 1, hi = cells.length;
    while (lo < hi) {
        const mid = Math.floor((lo + hi + 1) / 2);
        if (canCross(mid)) lo = mid;
        else hi = mid - 1;
    }
    return lo;
};

