class Solution:
    def minimumDeletions(self, s: str) -> int:
        n = len(s)
        left_close = [0] * (n + 1)
        open_count = 0
        for i, c in enumerate(s):
            if c == '(':
                open_count += 1
            else:
                if open_count > 0:
                    open_count -= 1
                else:
                    left_close[i+1] = left_close[i] + 1
                    continue
            left_close[i+1] = left_close[i]
        right_open = [0] * (n + 1)
        close_count = 0
        for i in range(n-1, -1, -1):
            if s[i] == ')':
                close_count += 1
            else:
                if close_count > 0:
                    close_count -= 1
                else:
                    right_open[i] = right_open[i+1] + 1
                    continue
            right_open[i] = right_open[i+1]
        return min(left_close[i] + right_open[i] for i in range(n+1))

solution_js:
var minimumDeletions = function(s) {
    const n = s.length;
    const leftClose = new Array(n + 1).fill(0);
    let open = 0;
    for (let i = 0; i < n; i++) {
        if (s[i] === '(') { open++; leftClose[i+1] = leftClose[i]; }
        else if (open > 0) { open--; leftClose[i+1] = leftClose[i]; }
        else { leftClose[i+1] = leftClose[i] + 1; }
    }
    const rightOpen = new Array(n + 1).fill(0);
    let close = 0;
    for (let i = n - 1; i >= 0; i--) {
        if (s[i] === ')') { close++; rightOpen[i] = rightOpen[i+1]; }
        else if (close > 0) { close--; rightOpen[i] = rightOpen[i+1]; }
        else { rightOpen[i] = rightOpen[i+1] + 1; }
    }
    let ans = Infinity;
    for (let i = 0; i <= n; i++) ans = Math.min(ans, leftClose[i] + rightOpen[i]);
    return ans;
};

