class Solution:
    def sortTransformedArray(self, nums: List[int], a: int, b: int, c: int) -> List[int]:
        def f(x): return a*x*x + b*x + c
        n = len(nums)
        result = [0] * n
        lo, hi = 0, n - 1
        idx = n - 1 if a >= 0 else 0
        while lo <= hi:
            lo_val, hi_val = f(nums[lo]), f(nums[hi])
            if a >= 0:
                if lo_val >= hi_val:
                    result[idx] = lo_val; lo += 1
                else:
                    result[idx] = hi_val; hi -= 1
                idx -= 1
            else:
                if lo_val <= hi_val:
                    result[idx] = lo_val; lo += 1
                else:
                    result[idx] = hi_val; hi -= 1
                idx += 1
        return result

solution_js:
var sortTransformedArray = function(nums, a, b, c) {
    const f = x => a*x*x + b*x + c;
    const n = nums.length;
    const result = new Array(n);
    let lo = 0, hi = n - 1;
    let idx = a >= 0 ? n - 1 : 0;
    while (lo <= hi) {
        const lv = f(nums[lo]), hv = f(nums[hi]);
        if (a >= 0) {
            if (lv >= hv) { result[idx--] = lv; lo++; }
            else { result[idx--] = hv; hi--; }
        } else {
            if (lv <= hv) { result[idx++] = lv; lo++; }
            else { result[idx++] = hv; hi--; }
        }
    }
    return result;
};

