class Solution:
    def maximumLength(self, nums: List[int]) -> int:
        n = len(nums)
        dp0 = dp1 = 1
        ans = 1
        for i in range(1, n):
            new_dp0 = dp0 + 1 if nums[i] >= nums[i-1] else 1
            new_dp1 = dp0 + 1  # replace nums[i] to fit
            if nums[i] >= nums[i-1]:
                new_dp1 = max(new_dp1, dp1 + 1)
            dp0, dp1 = new_dp0, new_dp1
            ans = max(ans, dp0, dp1)
        return ans

solution_js:
var maximumLength = function(nums) {
    let dp0 = 1, dp1 = 1, ans = 1;
    for (let i = 1; i < nums.length; i++) {
        let nd0 = nums[i] >= nums[i-1] ? dp0 + 1 : 1;
        let nd1 = dp0 + 1;
        if (nums[i] >= nums[i-1]) nd1 = Math.max(nd1, dp1 + 1);
        dp0 = nd0; dp1 = nd1;
        ans = Math.max(ans, dp0, dp1);
    }
    return ans;
};

