class Solution:
    def findSecretWord(self, words: List[str], master: 'Master') -> None:
        import random
        def match(a, b):
            return sum(x == y for x, y in zip(a, b))
        candidates = words[:]
        for _ in range(10):
            guess = random.choice(candidates)
            m = master.guess(guess)
            if m == 6: return
            candidates = [w for w in candidates if match(w, guess) == m]

