var findSecretWord = function(words, master) {
    function match(a, b) {
        let cnt = 0;
        for (let i = 0; i < 6; i++) if (a[i] === b[i]) cnt++;
        return cnt;
    }
    let candidates = [...words];
    for (let t = 0; t < 10; t++) {
        const guess = candidates[Math.floor(Math.random() * candidates.length)];
        const m = master.guess(guess);
        if (m === 6) return;
        candidates = candidates.filter(w => match(w, guess) === m);
    }
};

