class Solution:
    def findUnsortedSubarray(self, nums: List[int]) -> int:
        sorted_nums = sorted(nums)
        left, right = 0, len(nums) - 1
        while left < len(nums) and nums[left] == sorted_nums[left]:
            left += 1
        if left == len(nums):
            return 0
        while nums[right] == sorted_nums[right]:
            right -= 1
        return right - left + 1

