var solveSudoku = function(board) {
    const rows = Array.from({length:9}, () => new Set());
    const cols = Array.from({length:9}, () => new Set());
    const boxes = Array.from({length:9}, () => new Set());
    const empties = [];
    for (let r = 0; r < 9; r++)
        for (let c = 0; c < 9; c++) {
            if (board[r][c] === '.') empties.push([r, c]);
            else { const d = board[r][c]; rows[r].add(d); cols[c].add(d); boxes[Math.floor(r/3)*3+Math.floor(c/3)].add(d); }
        }
    function bt(idx) {
        if (idx === empties.length) return true;
        const [r, c] = empties[idx], b = Math.floor(r/3)*3+Math.floor(c/3);
        for (let d = 1; d <= 9; d++) {
            const s = String(d);
            if (!rows[r].has(s) && !cols[c].has(s) && !boxes[b].has(s)) {
                board[r][c] = s; rows[r].add(s); cols[c].add(s); boxes[b].add(s);
                if (bt(idx+1)) return true;
                board[r][c] = '.'; rows[r].delete(s); cols[c].delete(s); boxes[b].delete(s);
            }
        }
        return false;
    }
    bt(0);
};

