var countPaths = function(n, roads) {
    const MOD = BigInt(1e9 + 7);
    const graph = Array.from({length: n}, () => []);
    for (const [u, v, w] of roads) {
        graph[u].push([v, w]);
        graph[v].push([u, w]);
    }
    const dist = Array(n).fill(Infinity);
    const ways = Array(n).fill(0n);
    dist[0] = 0;
    ways[0] = 1n;
    // Min-heap simulation with sorted array (acceptable for interview; use a proper heap in production)
    const heap = [[0, 0]];
    const heapPush = (h, item) => { h.push(item); h.sort((a, b) => a[0] - b[0]); };
    while (heap.length) {
        const [d, u] = heap.shift();
        if (d > dist[u]) continue;
        for (const [v, w] of graph[u]) {
            const nd = d + w;
            if (nd < dist[v]) {
                dist[v] = nd;
                ways[v] = ways[u];
                heapPush(heap, [nd, v]);
            } else if (nd === dist[v]) {
                ways[v] = (ways[v] + ways[u]) % MOD;
            }
        }
    }
    return Number(ways[n - 1]);
};

