var exclusiveTime = function(n, logs) {
    const result = new Array(n).fill(0);
    const stack = [];
    let prevTime = 0;
    for (const log of logs) {
        const parts = log.split(':');
        const fid = parseInt(parts[0]);
        const typ = parts[1];
        const t = parseInt(parts[2]);
        if (typ === 'start') {
            if (stack.length > 0) result[stack[stack.length-1]] += t - prevTime;
            stack.push(fid);
            prevTime = t;
        } else {
            result[stack.pop()] += t - prevTime + 1;
            prevTime = t + 1;
        }
    }
    return result;
};

