class AutocompleteSystem:
    def __init__(self, sentences: List[str], times: List[int]):
        self.trie = {}
        self.cur = ''
        self.node = self.trie
        for s, t in zip(sentences, times):
            self._insert(s, t)

    def _insert(self, sentence, freq):
        node = self.trie
        for c in sentence:
            if c not in node:
                node[c] = {}
            node = node[c]
        node['#'] = node.get('#', 0) + freq

    def _search(self, node, prefix):
        res = []
        if '#' in node:
            res.append((node['#'], prefix))
        for c, child in node.items():
            if c != '#':
                res.extend(self._search(child, prefix + c))
        return res

    def input(self, c: str) -> List[str]:
        if c == '#':
            self._insert(self.cur, 1)
            self.cur = ''
            self.node = self.trie
            return []
        self.cur += c
        if self.node is None or c not in self.node:
            self.node = None
            return []
        self.node = self.node[c]
        results = self._search(self.node, self.cur)
        results.sort(key=lambda x: (-x[0], x[1]))
        return [s for _, s in results[:3]]

