from sortedcontainers import SortedList

class Solution:
    def oddEvenJumps(self, arr: list[int]) -> int:
        n = len(arr)
        next_odd = [None] * n
        next_even = [None] * n

        # Build next_odd and next_even using monotonic stack on sorted order
        def make_next(sorted_indices):
            result = [None] * n
            stack = []  # decreasing stack of indices
            for i in sorted_indices:
                while stack and stack[-1] < i:
                    result[stack.pop()] = i
                stack.append(i)
            return result

        sorted_by_val_asc = sorted(range(n), key=lambda i: (arr[i], i))
        sorted_by_val_desc = sorted(range(n), key=lambda i: (-arr[i], i))

        next_odd = make_next(sorted_by_val_asc)
        next_even = make_next(sorted_by_val_desc)

        odd = [False] * n
        even = [False] * n
        odd[-1] = even[-1] = True

        for i in range(n - 2, -1, -1):
            if next_odd[i] is not None:
                odd[i] = even[next_odd[i]]
            if next_even[i] is not None:
                even[i] = odd[next_even[i]]

        return sum(odd)

