var oddEvenJumps = function(arr) {
    const n = arr.length;
    const nextOdd = new Array(n).fill(-1);
    const nextEven = new Array(n).fill(-1);

    function makeNext(sortedIndices) {
        const result = new Array(n).fill(-1);
        const stack = [];
        for (const i of sortedIndices) {
            while (stack.length && stack[stack.length-1] < i) {
                result[stack.pop()] = i;
            }
            stack.push(i);
        }
        return result;
    }

    const sortedAsc = [...Array(n).keys()].sort((a,b) => arr[a] !== arr[b] ? arr[a]-arr[b] : a-b);
    const sortedDesc = [...Array(n).keys()].sort((a,b) => arr[a] !== arr[b] ? arr[b]-arr[a] : a-b);

    const no = makeNext(sortedAsc);
    const ne = makeNext(sortedDesc);

    const odd = new Array(n).fill(false);
    const even = new Array(n).fill(false);
    odd[n-1] = even[n-1] = true;

    for (let i = n-2; i >= 0; i--) {
        if (no[i] !== -1) odd[i] = even[no[i]];
        if (ne[i] !== -1) even[i] = odd[ne[i]];
    }

    return odd.filter(Boolean).length;
};

