var delNodes = function(root, to_delete) {
    const toDeleteSet = new Set(to_delete);
    const result = [];

    function dfs(node, isRoot) {
        if (!node) return null;
        const deleted = toDeleteSet.has(node.val);
        if (isRoot && !deleted) result.push(node);
        node.left = dfs(node.left, deleted);
        node.right = dfs(node.right, deleted);
        return deleted ? null : node;
    }

    dfs(root, true);
    return result;
};

var shortestAlternatingPaths = function(n, redEdges, blueEdges) {
    const red = Array.from({length: n}, () => []);
    const blue = Array.from({length: n}, () => []);
    for (const [u, v] of redEdges) red[u].push(v);
    for (const [u, v] of blueEdges) blue[u].push(v);

    const dist = new Array(n).fill(-1);
    dist[0] = 0;
    const visited = new Set(['0,0', '0,1']);
    const queue = [[0, 0, 0], [0, 0, 1]]; // [node, steps, lastColor]
    let head = 0;

    while (head < queue.length) {
        const [node, steps, color] = queue[head++];
        const neighbors = color === 0 ? blue[node] : red[node];
        const nextColor = 1 - color;
        for (const nb of neighbors) {
            const key = nb + ',' + nextColor;
            if (!visited.has(key)) {
                visited.add(key);
                if (dist[nb] === -1) dist[nb] = steps + 1;
                queue.push([nb, steps + 1, nextColor]);
            }
        }
    }
    return dist;
};

