var jobScheduling = function(startTime, endTime, profit) {
    const n = startTime.length;
    const jobs = Array.from({length: n}, (_, i) => [endTime[i], startTime[i], profit[i]]);
    jobs.sort((a, b) => a[0] - b[0]);
    const endTimes = [0], dp = [0];
    for (const [end, start, p] of jobs) {
        let lo = 0, hi = endTimes.length - 1;
        while (lo < hi) {
            const mid = (lo + hi + 1) >> 1;
            if (endTimes[mid] <= start) lo = mid; else hi = mid - 1;
        }
        const best = dp[lo] + p;
        if (best > dp[dp.length - 1]) { dp.push(best); endTimes.push(end); }
        else { dp.push(dp[dp.length - 1]); endTimes.push(end); }
    }
    return dp[dp.length - 1];
};

