class Solution:
    def isPossibleDivide(self, nums: List[int], k: int) -> bool:
        if len(nums) % k != 0:
            return False
        count = {}
        for n in nums:
            count[n] = count.get(n, 0) + 1
        for n in sorted(count):
            freq = count[n]
            if freq > 0:
                for i in range(k):
                    if count.get(n + i, 0) < freq:
                        return False
                    count[n + i] -= freq
        return True

