from functools import lru_cache

class Solution:
    def minimumDistance(self, word: str) -> int:
        def dist(a, b):
            if a == 26: return 0  # finger not yet placed
            r1, c1 = divmod(a, 6)
            r2, c2 = divmod(b, 6)
            return abs(r1 - r2) + abs(c1 - c2)

        n = len(word)

        @lru_cache(maxsize=None)
        def dp(i, f2):
            if i == n:
                return 0
            c = ord(word[i]) - ord('A')
            f1 = ord(word[i-1]) - ord('A') if i > 0 else 26
            opt1 = dist(f1, c) + dp(i + 1, f2)
            opt2 = dist(f2, c) + dp(i + 1, f1)
            return min(opt1, opt2)

        return dp(0, 26)

solution_js:
var minimumDistance = function(word) {
    const dist = (a, b) => {
        if (a === 26) return 0;
        return Math.abs(Math.floor(a/6) - Math.floor(b/6)) + Math.abs(a%6 - b%6);
    };
    const n = word.length;
    const memo = new Map();

    function dp(i, f2) {
        if (i === n) return 0;
        const key = `${i},${f2}`;
        if (memo.has(key)) return memo.get(key);
        const c = word.charCodeAt(i) - 65;
        const f1 = i > 0 ? word.charCodeAt(i-1) - 65 : 26;
        const opt1 = dist(f1, c) + dp(i+1, f2);
        const opt2 = dist(f2, c) + dp(i+1, f1);
        const res = Math.min(opt1, opt2);
        memo.set(key, res);
        return res;
    }

    return dp(0, 26);
};

