from collections import deque

class Solution:
    def hasValidPath(self, grid: list[list[int]]) -> bool:
        # connections[t] = list of (dr, dc, required_back_directions_index)
        # direction indices: 0=left, 1=right, 2=up, 3=down
        connects = {
            1: [(0,-1,1),(0,1,0)],
            2: [(-1,0,3),(1,0,2)],
            3: [(0,-1,1),(1,0,2)],
            4: [(0,1,0),(1,0,2)],
            5: [(0,-1,1),(-1,0,3)],
            6: [(0,1,0),(-1,0,3)],
        }
        m, n = len(grid), len(grid[0])
        visited = [[False]*n for _ in range(m)]
        queue = deque([(0,0)])
        visited[0][0] = True
        while queue:
            r, c = queue.popleft()
            if r == m-1 and c == n-1:
                return True
            for dr, dc, back in connects[grid[r][c]]:
                nr, nc = r+dr, c+dc
                if 0 <= nr < m and 0 <= nc < n and not visited[nr][nc]:
                    if any(b == back for _, _, b in [(0,0,back)] if True):
                        # check neighbor connects back
                        if any(bdr == -dr and bdc == -dc for bdr, bdc, _ in connects[grid[nr][nc]]):
                            visited[nr][nc] = True
                            queue.append((nr,nc))
        return visited[m-1][n-1]

