class Solution:
    def numSteps(self, s: str) -> int:
        steps = 0
        carry = 0
        for i in range(len(s) - 1, 0, -1):
            bit = int(s[i]) + carry
            if bit % 2 == 1:  # odd: need to add 1 (2 ops: +1 then /2)
                steps += 2
                carry = 1
            else:  # even: just divide by 2
                steps += 1
        steps += carry  # any remaining carry adds 1 extra step
        return steps

