var minSubarray = function(nums, p) {
    const total = nums.reduce((a, b) => a + b, 0);
    const target = Number(BigInt(total) % BigInt(p));
    if (target === 0) return 0;

    const prefixMap = new Map([[0, -1]]);
    let cur = 0;
    let minLen = nums.length;

    for (let i = 0; i < nums.length; i++) {
        cur = (cur + nums[i]) % p;
        const need = ((cur - target) % p + p) % p;
        if (prefixMap.has(need)) {
            minLen = Math.min(minLen, i - prefixMap.get(need));
        }
        prefixMap.set(cur, i);
    }

    return minLen < nums.length ? minLen : -1;
};

