    for (let i = 0; i < Math.floor(n / 2); i++) {
        let a = nums[i], b = nums[n - 1 - i];
        const lo = Math.min(a, b), hi = Math.max(a, b);
        diff[2] += 2;
        diff[2 * limit + 1] -= 2;
        diff[lo + 1] -= 1;
        diff[hi + limit + 1] += 1;
        diff[a + b] -= 1;
        diff[a + b + 1] += 1;
    }

    let ans = n, cur = 0;
    for (let s = 2; s <= 2 * limit; s++) {
        cur += diff[s];
        ans = Math.min(ans, cur);
    }
    return ans;
};

