from typing import List

class Solution:
    def rotateTheBox(self, box: List[List[str]]) -> List[List[str]]:
        rows, cols = len(box), len(box[0])
        # Apply gravity (stones fall right)
        for r in range(rows):
            empty = cols - 1
            for c in range(cols - 1, -1, -1):
                if box[r][c] == '*':
                    empty = c - 1
                elif box[r][c] == '#':
                    box[r][c] = '.'
                    box[r][empty] = '#'
                    empty -= 1
        # Rotate 90 degrees clockwise
        result = [['.'] * rows for _ in range(cols)]
        for r in range(rows):
            for c in range(cols):
                result[c][rows - 1 - r] = box[r][c]
        return result

solution_js:
var rotateTheBox = function(box) {
    const rows = box.length, cols = box[0].length;
    for (let r = 0; r < rows; r++) {
        let empty = cols - 1;
        for (let c = cols - 1; c >= 0; c--) {
            if (box[r][c] === '*') {
                empty = c - 1;
            } else if (box[r][c] === '#') {
                box[r][c] = '.';
                box[r][empty] = '#';
                empty--;
            }
        }
    }
    const result = Array.from({length: cols}, () => new Array(rows).fill('.'));
    for (let r = 0; r < rows; r++) {
        for (let c = 0; c < cols; c++) {
            result[c][rows - 1 - r] = box[r][c];
        }
    }
    return result;
};

var getBiggestThree = function(grid) {
    const m = grid.length, n = grid[0].length;
    const diag1 = Array.from({length: m+2}, () => new Array(n+2).fill(0));
    const diag2 = Array.from({length: m+2}, () => new Array(n+2).fill(0));

    for (let i = 1; i <= m; i++) {
        for (let j = 1; j <= n; j++) {
            diag1[i][j] = diag1[i-1][j-1] + grid[i-1][j-1];
            diag2[i][j] = diag2[i-1][j+1] + grid[i-1][j-1];
        }
    }

    function rhombusSum(r, c, k) {
        if (k === 0) return grid[r][c];
        const [r1,c1] = [r-k, c], [r2,c2] = [r, c+k];
        const [r3,c3] = [r+k, c], [r4,c4] = [r, c-k];
        const s1 = diag1[r2+1][c2+1] - diag1[r1+1][c1+1];
        const s2 = diag2[r3+1][c3+1] - diag2[r2+1][c2+1];
        const s3 = diag1[r3+1][c3+1] - diag1[r4][c4];
        const s4 = diag2[r4+1][c4+1] - diag2[r1+1][c1+1];
        return s1+s2+s3+s4 - grid[r1][c1] - grid[r2][c2] - grid[r3][c3] - grid[r4][c4];
    }

    const candidates = new Set();
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            const maxK = Math.min(i, j, m-1-i, n-1-j);
            for (let k = 0; k <= maxK; k++) {
                candidates.add(rhombusSum(i, j, k));
            }
        }
    }
    return [...candidates].sort((a,b) => b-a).slice(0, 3);
};

var minFlips = function(s) {
    const n = s.length;
    const s2 = s + s;
    const t1 = Array.from({length: 2*n}, (_, i) => i % 2 === 0 ? '0' : '1').join('');
    const t2 = Array.from({length: 2*n}, (_, i) => i % 2 === 0 ? '1' : '0').join('');
    let d1 = 0, d2 = 0;
    for (let i = 0; i < n; i++) { if (s2[i] !== t1[i]) d1++; if (s2[i] !== t2[i]) d2++; }
    let ans = Math.min(d1, d2);
    for (let i = n; i < 2*n; i++) {
        if (s2[i] !== t1[i]) d1++; if (s2[i] !== t2[i]) d2++;
        if (s2[i-n] !== t1[i-n]) d1--; if (s2[i-n] !== t2[i-n]) d2--;
        ans = Math.min(ans, d1, d2);
    }
    return ans;
};

