from typing import List

class Solution:
    def rotateGrid(self, grid: List[List[int]], k: int) -> List[List[int]]:
        m, n = len(grid), len(grid[0])
        layers = min(m, n) // 2

        for layer in range(layers):
            top, left = layer, layer
            bottom, right = m - 1 - layer, n - 1 - layer
            ring = []
            # top row left to right
            for c in range(left, right + 1):
                ring.append(grid[top][c])
            # right col top+1 to bottom
            for r in range(top + 1, bottom + 1):
                ring.append(grid[r][right])
            # bottom row right-1 to left
            for c in range(right - 1, left - 1, -1):
                ring.append(grid[bottom][c])
            # left col bottom-1 to top+1
            for r in range(bottom - 1, top, -1):
                ring.append(grid[r][left])

            L = len(ring)
            rot = k % L
            ring = ring[rot:] + ring[:rot]

            idx = 0
            for c in range(left, right + 1):
                grid[top][c] = ring[idx]; idx += 1
            for r in range(top + 1, bottom + 1):
                grid[r][right] = ring[idx]; idx += 1
            for c in range(right - 1, left - 1, -1):
                grid[bottom][c] = ring[idx]; idx += 1
            for r in range(bottom - 1, top, -1):
                grid[r][left] = ring[idx]; idx += 1

        return grid

solution_js:
var rotateGrid = function(grid, k) {
    const m = grid.length, n = grid[0].length;
    const layers = Math.floor(Math.min(m, n) / 2);
    for (let layer = 0; layer < layers; layer++) {
        const top = layer, left = layer;
        const bottom = m - 1 - layer, right = n - 1 - layer;
        const ring = [];
        for (let c = left; c <= right; c++) ring.push(grid[top][c]);
        for (let r = top + 1; r <= bottom; r++) ring.push(grid[r][right]);
        for (let c = right - 1; c >= left; c--) ring.push(grid[bottom][c]);
        for (let r = bottom - 1; r > top; r--) ring.push(grid[r][left]);
        const L = ring.length;
        const rot = k % L;
        const rotated = [...ring.slice(rot), ...ring.slice(0, rot)];
        let idx = 0;
        for (let c = left; c <= right; c++) grid[top][c] = rotated[idx++];
        for (let r = top + 1; r <= bottom; r++) grid[r][right] = rotated[idx++];
        for (let c = right - 1; c >= left; c--) grid[bottom][c] = rotated[idx++];
        for (let r = bottom - 1; r > top; r--) grid[r][left] = rotated[idx++];
    }
    return grid;
};

