from typing import List

class Solution:
    def subArrayRanges(self, nums: List[int]) -> int:
        n = len(nums)

        def sum_of_extremes(is_max: bool) -> int:
            total = 0
            stack = []
            for i in range(n + 1):
                while stack and (i == n or (nums[stack[-1]] < nums[i] if is_max else nums[stack[-1]] > nums[i])):
                    mid = stack.pop()
                    left = stack[-1] if stack else -1
                    total += nums[mid] * (i - mid) * (mid - left)
                stack.append(i)
            return total

        return sum_of_extremes(True) - sum_of_extremes(False)

