            if (i % 2 === 0) {
                if (mat[i][j] !== mat[i][(j + shift) % n]) return false;
            } else {
                if (mat[i][j] !== mat[i][((j - shift) % n + n) % n]) return false;
            }
        }
    }
    return true;
};

