var maximumSubarraySum = function(nums, k) {
    const n = nums.length;
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) prefix[i+1] = prefix[i] + nums[i];

    const minPrefix = new Map();
    let ans = -Infinity, found = false;

    for (let j = 0; j < n; j++) {
        const v = nums[j];
        for (const target of [v-1, v, v+1]) {
            if (minPrefix.has(target)) {
                ans = Math.max(ans, prefix[j+1] - minPrefix.get(target));
                found = true;
            }
        }
        if (!minPrefix.has(v) || prefix[j] < minPrefix.get(v)) {
            minPrefix.set(v, prefix[j]);
        }
    }
    return found ? ans : 0;
};

