class Solution:
    def numberOfStableArrays(self, zero: int, one: int, limit: int) -> int:
        MOD = 10**9 + 7
        # dp[i][j][k]: arrays with i zeros, j ones, ending in k
        dp = [[[0, 0] for _ in range(one + 1)] for _ in range(zero + 1)]
        dp[0][0][0] = dp[0][0][1] = 1  # empty base
        # Actually use iterative build
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def solve(z, o, last):
            if z == 0 and o == 0:
                return 1
            res = 0
            if last == 0 and z > 0:
                for run in range(1, min(limit, z) + 1):
                    res += solve(z - run, o, 1)
            elif last == 1 and o > 0:
                for run in range(1, min(limit, o) + 1):
                    res += solve(z, o - run, 0)
            return res % MOD
        return (solve(zero, one, 0) + solve(zero, one, 1)) % MOD

