import math
class Solution:
    def minNumberOfSeconds(self, mountainHeight: int, workerTimes: list) -> int:
        def max_reduction(worker_time, T):
            # h*(h+1)/2 <= T / worker_time
            budget = T // worker_time
            # solve h*(h+1)/2 <= budget => h <= (-1 + sqrt(1+8*budget))/2
            h = int((-1 + math.isqrt(1 + 8 * budget)) // 2)
            return h
        def feasible(T):
            total = sum(max_reduction(wt, T) for wt in workerTimes)
            return total >= mountainHeight
        lo, hi = 1, min(workerTimes) * mountainHeight * (mountainHeight + 1) // 2
        while lo < hi:
            mid = (lo + hi) // 2
            if feasible(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo

