var minNumberOfSeconds = function(mountainHeight, workerTimes) {
    function maxReduction(wt, T) {
        const budget = Math.floor(T / wt);
        return Math.floor((-1 + Math.sqrt(1 + 8 * budget)) / 2);
    }
    function feasible(T) {
        let total = 0;
        for (const wt of workerTimes) total += maxReduction(wt, T);
        return total >= mountainHeight;
    }
    const minWt = Math.min(...workerTimes);
    let lo = 1n, hi = BigInt(minWt) * BigInt(mountainHeight) * BigInt(mountainHeight + 1) / 2n;
    while (lo < hi) {
        const mid = (lo + hi) / 2n;
        if (feasible(Number(mid))) hi = mid; else lo = mid + 1n;
    }
    return Number(lo);
};

