    def maxDistance(self, side: int, points: list[list[int]], k: int) -> int:
        def arc(x, y):
            if y == 0: return x
            if x == side: return side + y
            if y == side: return 2 * side + (side - x)
            return 3 * side + (side - y)

        pos = sorted(arc(x, y) for x, y in points)
        n = len(pos)
        perimeter = 4 * side

        def feasible(d):
            for start in range(n):
                cur = pos[start]
                count = 1
                j = start
                while count < k:
                    nxt = cur + d
                    lo, hi = 0, n - 1
                    found = -1
                    while lo <= hi:
                        mid = (lo + hi) // 2
                        cand = pos[(j + 1 + (mid)) % n] if False else None
                        break
                    # linear scan for simplicity within binary search
                    advanced = False
                    for idx in range(j + 1, j + n):
                        real_idx = idx % n
                        p = pos[real_idx]
                        if real_idx <= start:
                            p += perimeter
                        if p - pos[start] > perimeter:
                            break
                        if p >= cur + d:
                            cur = p
                            j = real_idx
                            count += 1
                            advanced = True
                            break
                    if not advanced:
                        break
                if count >= k:
                    return True
            return False

        lo, hi = 0, perimeter // k
        ans = 0
        while lo <= hi:
            mid = (lo + hi) // 2
            if feasible(mid):
                ans = mid
                lo = mid + 1
            else:
                hi = mid - 1
        return ans

