class Solution:
    def generateString(self, str1: str, str2: str) -> str:
        n, m = len(str1), len(str2)
        result = ['a'] * (n + m - 1)
        # Mark forced positions from 'T' constraints
        forced = [False] * (n + m - 1)
        for i in range(n):
            if str1[i] == 'T':
                for j in range(m):
                    if forced[i + j] and result[i + j] != str2[j]:
                        return ''
                    result[i + j] = str2[j]
                    forced[i + j] = True
        # For 'F' positions ensure str2 is NOT placed (change first char if needed)
        for i in range(n):
            if str1[i] == 'F':
                # The window i..i+m-1 must NOT equal str2
                # If the window is currently all matching str2, change a non-forced pos
                match = all(result[i+j] == str2[j] for j in range(m))
                if match:
                    # Find a non-forced position in window to change
                    changed = False
                    for j in range(m - 1, -1, -1):
                        if not forced[i + j]:
                            result[i + j] = 'b' if str2[j] == 'a' else 'a'
                            changed = True
                            break
                    if not changed:
                        return ''
        return ''.join(result)

