var applySubstitutions = function(replacements, text) {
    const rules = new Map(replacements);
    const memo = new Map();

    function expand(s) {
        if (memo.has(s)) return memo.get(s);
        let result = '';
        let i = 0;
        while (i < s.length) {
            if (s[i] === '%') {
                const j = s.indexOf('%', i + 1);
                const varName = s.slice(i + 1, j);
                result += expand(rules.get(varName));
                i = j + 1;
            } else {
                result += s[i];
                i++;
            }
        }
        memo.set(s, result);
        return result;
    }

    return expand(text);
};

var solveQueries = function(nums, queries) {
    const n = nums.length;
    const idxMap = new Map();
    for (let i = 0; i < n; i++) {
        if (!idxMap.has(nums[i])) idxMap.set(nums[i], []);
        idxMap.get(nums[i]).push(i);
    }

    const bisectLeft = (arr, val) => {
        let lo = 0, hi = arr.length;
        while (lo < hi) { const mid = (lo+hi)>>1; if (arr[mid] < val) lo=mid+1; else hi=mid; }
        return lo;
    };

    return queries.map(q => {
        const idxs = idxMap.get(nums[q]);
        if (idxs.length === 1) return -1;
        const pos = bisectLeft(idxs, q);
        let best = Infinity;
        for (const delta of [-1, 0, 1]) {
            const p = ((pos + delta) % idxs.length + idxs.length) % idxs.length;
            const j = idxs[p];
            if (j !== q) best = Math.min(best, Math.min(Math.abs(j-q), n-Math.abs(j-q)));
        }
        return best === Infinity ? -1 : best;
    });
};

