class Solution:
    def canPartitionGrid(self, grid: List[List[int]]) -> bool:
        from collections import defaultdict
        m, n = len(grid), len(grid[0])
        total = sum(grid[i][j] for i in range(m) for j in range(n))
        # Horizontal cuts
        row_sum = 0
        for i in range(m - 1):
            row_sum += sum(grid[i])
            other = total - row_sum
            diff = row_sum - other
            if diff == 0:
                return True
            if diff % 2 == 0:
                target = diff // 2
                boundary = set(grid[i]) | set(grid[i+1])
                if target > 0 and target in boundary:
                    return True
                if target < 0 and (-target) in boundary:
                    return True
        # Vertical cuts
        col_sum = 0
        for j in range(n - 1):
            col_sum += sum(grid[i][j] for i in range(m))
            other = total - col_sum
            diff = col_sum - other
            if diff == 0:
                return True
            if diff % 2 == 0:
                target = diff // 2
                boundary = set(grid[i][j] for i in range(m)) | set(grid[i][j+1] for i in range(m))
                if target > 0 and target in boundary:
                    return True
                if target < 0 and (-target) in boundary:
                    return True
        return False

