var canPartitionGrid = function(grid) {
    const m = grid.length, n = grid[0].length;
    let total = 0;
    for (let i = 0; i < m; i++) for (let j = 0; j < n; j++) total += grid[i][j];
    // Horizontal cuts
    let rowSum = 0;
    for (let i = 0; i < m - 1; i++) {
        for (let j = 0; j < n; j++) rowSum += grid[i][j];
        const other = total - rowSum;
        const diff = rowSum - other;
        if (diff === 0) return true;
        if (diff % 2 === 0) {
            const target = Math.abs(diff / 2);
            const boundary = new Set([...grid[i], ...grid[i+1]]);
            if (boundary.has(target)) return true;
        }
    }
    // Vertical cuts
    let colSum = 0;
    for (let j = 0; j < n - 1; j++) {
        for (let i = 0; i < m; i++) colSum += grid[i][j];
        const other = total - colSum;
        const diff = colSum - other;
        if (diff === 0) return true;
        if (diff % 2 === 0) {
            const target = Math.abs(diff / 2);
            const boundary = new Set([...Array.from({length: m}, (_, i) => grid[i][j]), ...Array.from({length: m}, (_, i) => grid[i][j+1])]);
            if (boundary.has(target)) return true;
        }
    }
    return false;
};

