var findCoins = function(ways) {
    const n = ways.length;
    const dp = new Array(n + 1).fill(0);
    dp[0] = 1;
    const coins = [];

    for (let c = 1; c <= n; c++) {
        if (dp[c] !== ways[c-1]) {
            coins.push(c);
            for (let j = c; j <= n; j++) dp[j] += dp[j-c];
        }
    }

    for (let i = 0; i < n; i++) {
        if (dp[i+1] !== ways[i]) return [];
    }
    return coins;
};

