class Solution:
    def maxStability(self, n: int, edges: list, k: int) -> int:
        def find(p, x):
            while p[x] != x: p[x] = p[p[x]]; x = p[x]
            return x
        def union(p, rank, x, y):
            rx, ry = find(p, x), find(p, y)
            if rx == ry: return False
            if rank[rx] < rank[ry]: rx, ry = ry, rx
            p[ry] = rx
            if rank[rx] == rank[ry]: rank[rx] += 1
            return True
        def feasible(t):
            p = list(range(n + 1))
            rank = [0] * (n + 1)
            upgrades_used = 0
            components = n
            for w, u, v in sorted_edges:
                if w >= t:
                    if union(p, rank, u, v):
                        components -= 1
                else:
                    if upgrades_used < k:
                        if union(p, rank, u, v):
                            components -= 1
                            upgrades_used += 1
            return components == 1
        sorted_edges = sorted([(w, u, v) for u, v, w in edges], reverse=True)
        weights = sorted(set(w for u, v, w in edges))
        lo, hi = 0, len(weights) - 1
        ans = weights[0] if weights else 0
        while lo <= hi:
            mid = (lo + hi) // 2
            if feasible(weights[mid]):
                ans = weights[mid]
                lo = mid + 1
            else:
                hi = mid - 1
        return ans

