var maxStability = function(n, edges, k) {
    function find(p, x) { while (p[x] !== x) { p[x] = p[p[x]]; x = p[x]; } return x; }
    function union(p, rank, x, y) {
        let rx = find(p, x), ry = find(p, y);
        if (rx === ry) return false;
        if (rank[rx] < rank[ry]) [rx, ry] = [ry, rx];
        p[ry] = rx; if (rank[rx] === rank[ry]) rank[rx]++;
        return true;
    }
    const sorted = edges.map(([u,v,w]) => [w,u,v]).sort((a,b) => b[0]-a[0]);
    const weights = [...new Set(edges.map(([u,v,w])=>w))].sort((a,b)=>a-b);
    function feasible(t) {
        const p = Array.from({length:n+1},(_,i)=>i), rank = new Array(n+1).fill(0);
        let upg = 0, comp = n;
        for (const [w,u,v] of sorted) {
            if (w >= t) { if (union(p,rank,u,v)) comp--; }
            else if (upg < k) { if (union(p,rank,u,v)) { comp--; upg++; } }
        }
        return comp === 1;
    }
    let lo = 0, hi = weights.length-1, ans = weights[0] || 0;
    while (lo <= hi) {
        const mid = (lo+hi)>>1;
        if (feasible(weights[mid])) { ans = weights[mid]; lo = mid+1; } else hi = mid-1;
    }
    return ans;
};

