var minCost = function(nums, costs) {
    const n = nums.length;
    const graph = Array.from({length: n}, () => []);
    let stack = [];
    for (let i = 0; i < n; i++) {
        while (stack.length && nums[stack[stack.length-1]] < nums[i]) {
            graph[stack.pop()].push(i);
        }
        if (stack.length) graph[stack[stack.length-1]].push(i);
        stack.push(i);
    }
    stack = [];
    for (let i = 0; i < n; i++) {
        while (stack.length && nums[stack[stack.length-1]] > nums[i]) {
            graph[stack.pop()].push(i);
        }
        if (stack.length) graph[stack[stack.length-1]].push(i);
        stack.push(i);
    }
    const dist = new Array(n).fill(Infinity);
    dist[0] = 0;
    // Simple Dijkstra with array (ok for this problem size)
    const visited = new Array(n).fill(false);
    for (let iter = 0; iter < n; iter++) {
        let u = -1;
        for (let i = 0; i < n; i++) if (!visited[i] && (u === -1 || dist[i] < dist[u])) u = i;
        if (dist[u] === Infinity) break;
        visited[u] = true;
        for (const v of graph[u]) {
            if (dist[u] + costs[v] < dist[v]) dist[v] = dist[u] + costs[v];
        }
    }
    return dist[n-1];
};

