var minOperations = function(nums) {
    const n = nums.length;
    const maxVal = Math.max(...nums, 3);
    const sieve = new Array(maxVal + 1).fill(true);
    sieve[0] = sieve[1] = false;
    for (let i = 2; i * i <= maxVal; i++) {
        if (sieve[i]) for (let j = i*i; j <= maxVal; j += i) sieve[j] = false;
    }

    const evenCnt = new Map(), oddCnt = new Map();
    for (let i = 0; i < n; i++) {
        const m = i % 2 === 0 ? evenCnt : oddCnt;
        m.set(nums[i], (m.get(nums[i]) || 0) + 1);
    }

    const topPrimes = (map) => [...map.entries()]
        .filter(([v]) => v <= maxVal && sieve[v])
        .sort((a,b) => b[1]-a[1]).slice(0,2);

    const ep = topPrimes(evenCnt), op = topPrimes(oddCnt);
    if (!ep.length) ep.push([2, 0]);
    if (!op.length) op.push([3, 0]);

    let best = Infinity;
    for (const [ev, ec] of ep)
        for (const [ov, oc] of op)
            if (ev !== ov) best = Math.min(best, n - ec - oc);

    return best === Infinity ? n : best;
};

