class Solution:
    def countKthRoots(self, lo: int, hi: int, k: int) -> int:
        import math
        def kth_root_floor(n: int) -> int:
            if n < 0:
                return 0
            r = int(round(n ** (1 / k)))
            # adjust for floating-point imprecision
            while (r + 1) ** k <= n:
                r += 1
            while r > 0 and r ** k > n:
                r -= 1
            return r

        r_lo = kth_root_floor(lo - 1) + 1  # ceiling root of lo
        r_hi = kth_root_floor(hi)           # floor root of hi
        return max(0, r_hi - r_lo + 1)

solution_js:
var countKthRoots = function(lo, hi, k) {
    function kthRootFloor(n) {
        if (n < 0) return 0;
        let r = Math.round(Math.pow(n, 1 / k));
        while (Math.pow(r + 1, k) <= n) r++;
        while (r > 0 && Math.pow(r, k) > n) r--;
        return r;
    }
    const rLo = kthRootFloor(lo - 1) + 1;
    const rHi = kthRootFloor(hi);
    return Math.max(0, rHi - rLo + 1);
};
